const error = $input.first().json;

const execution = error.execution || {};
const workflow = error.workflow || {};
const errorMsg = execution.error?.message || 'Unknown error';
const failedNode = execution.lastNodeExecuted || 'unknown';

// Only alert for critical workflows
const MONITORED = [
  'Telegram Task Intake',
  'Dev-Loop Orchestrator',
  'SMS Inbound',
  'AI Booking Worker',
  'Calendar Sync'
];

const wfName = workflow.name || 'Unknown Workflow';
const isMonitored = MONITORED.some(m => wfName.includes(m));

if (!isMonitored) {
  return [];
}

let msg = '❌ WORKFLOW FAILURE\n\n';
msg += 'Workflow: ' + wfName + '\n';
msg += 'Failed Node: ' + failedNode + '\n';
msg += 'Error: ' + errorMsg.substring(0, 500) + '\n';
msg += 'Execution ID: ' + (execution.id || 'n/a') + '\n';
msg += 'Time: ' + new Date().toISOString() + '\n';
msg += '\nCheck: https://bandomasis.app.n8n.cloud';

return [{ json: { chatId: '8747048300', text: msg } }];
